import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";

export default async function AdminPage() {
  const session = await getServerSession(authOptions);
  if (!session || (session.user as any).role !== "admin") redirect("/dashboard");

  return (
    <section className="container">
      <div className="row" style={{ marginBottom: '20px' }}>
        <h1>Admin Panel 🚨</h1>
        <p className="muted">ระบบวิเคราะห์ข้อมูล Office Syndrome สำหรับผู้ดูแลระบบ</p>
      </div>

      <div className="grid">
        <article className="card">
          <h3>สรุปข้อมูลผู้ใช้งาน</h3>
          <p>จำนวนพนักงานในระบบ: <b>24 คน</b></p>
          <p>สถานะ Database: <span style={{ color: '#10b981' }}>พร้อมทำงาน</span></p>
        </article>

        <article className="card">
          <h3>วิเคราะห์ความเสี่ยงองค์กร</h3>
          <p>อาการยอดฮิต: <b>ปวดหลัง (68%)</b></p>
          <button className="btn" style={{ marginTop: '15px', background: '#fee2e2', color: '#ef4444', border: 'none', width: '100%' }}>
            ส่งแจ้งเตือนเตือนพนักงานให้ลุกยืดเส้น
          </button>
        </article>
      </div>
    </section>
  );
}